    cin>>a1>>b;
    len=a1.size();
    for(int i=1;i<=len;i++)a[i]=a1[i-1]-'0';
    for(int i=1;i<=len;i++)c[i]=(d*10+a[i])/b,d=(d*10+a[i])%b;
	lenc=1;
    while(c[lenc]==0&&lenc<len)lenc++;
    for(int i=lenc;i<=len;i++)cout<<c[i];
